static void
initpath(const char *pathstr)
{
	int count = 1;
	const char *p;
	char *s, *rest;
	int i = 0;

	if (pathstr == NULL || *pathstr == '\0') {
		path_dirs = malloc(2 * sizeof(char *));
		path_dirs[0] = strdup(".");
		path_dirs[1] = NULL;
		return;
	}

	for (p = pathstr; *p; p++) {
		if (*p == ':')
			count++;
	}

	path_dirs = malloc((count + 1) * sizeof(char *));
	s = strdup(pathstr);
	rest = s;

	while (i < count) {
		char *colon = strchr(rest, ':');
		if (colon) {
			*colon = '\0';
			if (*rest == '\0')
				path_dirs[i++] = strdup(".");
			else
				path_dirs[i++] = strdup(rest);
			rest = colon + 1;
		} else {
			if (*rest == '\0')
				path_dirs[i++] = strdup(".");
			else
				path_dirs[i++] = strdup(rest);
			break;
		}
	}
	path_dirs[i] = NULL;
	free(s);
}

