static void
eval(const char *cmdline) 
{
	char *argv[MAXARGS];
	char buf[MAXLINE];
	bool bg;
	pid_t pid;
	sigset_t mask_all, mask_one, prev_one;

	sigfillset(&mask_all);
	sigemptyset(&mask_one);
	sigaddset(&mask_one, SIGCHLD);

	strcpy(buf, cmdline);
	bg = parseline(buf, argv);

	if (argv[0] == NULL)
		return;

	if (!builtin_cmd(argv)) {
		sigprocmask(SIG_BLOCK, &mask_one, &prev_one);
		if ((pid = fork()) == 0) {
			sigprocmask(SIG_SETMASK, &prev_one, NULL);
			setpgid(0, 0);

			char *executable = argv[0];
			char full_path[MAXLINE];
			if (strchr(executable, '/') == NULL && path_dirs != NULL) {
				int i;
				for (i = 0; path_dirs[i] != NULL; i++) {
					snprintf(full_path, MAXLINE, "%s/%s",
					    path_dirs[i], executable);
					if (access(full_path, X_OK) == 0) {
						executable = full_path;
						break;
					}
				}
			}

			if (execve(executable, argv, environ) < 0) {
				printf("%s: Command not found\n", argv[0]);
				exit(0);
			}
		}

		sigprocmask(SIG_BLOCK, &mask_all, NULL);
		addjob(jobs, pid, bg ? BG : FG, cmdline);
		sigprocmask(SIG_SETMASK, &prev_one, NULL);

		if (!bg)
			waitfg(pid);
		else
			printf("[%d] (%d) %s", pid2jid(pid), (int)pid,
			    cmdline);
	}
}

static void
do_bgfg(char **argv) 
{
	char *id = argv[1];
	JobP job = NULL;

	if (id == NULL) {
		printf("%s command requires PID or %%jobid argument\n", argv[0]);
		return;
	}

	if (id[0] == '%') {
		int jid = atoi(&id[1]);
		job = getjobjid(jobs, jid);
		if (job == NULL) {
			printf("%s: No such job\n", id);
			return;
		}
	} else if (isdigit(id[0])) {
		pid_t pid = atoi(id);
		job = getjobpid(jobs, pid);
		if (job == NULL) {
			printf("(%s): No such process\n", id);
			return;
		}
	} else {
		printf("%s: argument must be a PID or %%jobid\n", argv[0]);
		return;
	}

	if (strcmp(argv[0], "bg") == 0) {
		job->state = BG;
		kill(-job->pid, SIGCONT);
		printf("[%d] (%d) %s", job->jid, (int)job->pid,
		    job->cmdline);
	} else {
		job->state = FG;
		kill(-job->pid, SIGCONT);
		waitfg(job->pid);
	}
}

